import React, { useState, useContext } from 'react';
import { AdminContext } from '../../context/AdminContext';
import './Login.css';

function Login() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [rememberMe, setRememberMe] = useState(false);
    const [alertMessage, setAlertMessage] = useState({ type: '', message: '' });
    const { adminLogin, loading } = useContext(AdminContext);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setAlertMessage({ type: '', message: '' });
        
        const result = await adminLogin(email, password);
        
        if (!result.success) {
            setAlertMessage({
                type: 'error',
                message: result.message || "Login failed"
            });
        }
    };

    const copyCredentials = (text) => {
        navigator.clipboard.writeText(text);
        setAlertMessage({
            type: 'success',
            message: 'Copied to clipboard!'
        });
        setTimeout(() => setAlertMessage({ type: '', message: '' }), 2000);
    };

    return (
        <div className="login-page">
            <div className="login-container">
                {/* Left Side - Branding */}
                <div className="login-branding">
                    <div className="brand-icon">🍔</div>
                    <h1>Admin Dashboard</h1>
                    <p>Manage your food delivery platform with ease. Track orders, manage menu, and grow your business.</p>
                    
                    <div className="brand-features">
                        <div className="feature-item">
                            <span className="feature-icon">📊</span>
                            <div className="feature-text">
                                <h3>Real-time Analytics</h3>
                                <p>Monitor your business performance</p>
                            </div>
                        </div>
                        
                        <div className="feature-item">
                            <span className="feature-icon">📦</span>
                            <div className="feature-text">
                                <h3>Order Management</h3>
                                <p>Track and manage all orders</p>
                            </div>
                        </div>
                        
                        <div className="feature-item">
                            <span className="feature-icon">👥</span>
                            <div className="feature-text">
                                <h3>Customer Insights</h3>
                                <p>Understand your customers better</p>
                            </div>
                        </div>
                        
                        <div className="feature-item">
                            <span className="feature-icon">🚀</span>
                            <div className="feature-text">
                                <h3>Easy Scaling</h3>
                                <p>Grow your business effortlessly</p>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Right Side - Login Form */}
                <div className="login-form-container">
                    <div className="form-header">
                        <h2>Welcome Back</h2>
                        <p>Please login to your account</p>
                    </div>

                    {alertMessage.message && (
                        <div className={`alert-message ${alertMessage.type}`}>
                            {alertMessage.type === 'error' ? '❌' : '✅'} {alertMessage.message}
                        </div>
                    )}

                    <form onSubmit={handleSubmit} className="login-form">
                        <div className="input-group">
                            <span className="input-icon">📧</span>
                            <input
                                type="email"
                                placeholder="Email address"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                required
                                disabled={loading}
                            />
                        </div>

                        <div className="input-group">
                            <span className="input-icon">🔒</span>
                            <input
                                type={showPassword ? "text" : "password"}
                                placeholder="Password"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                                disabled={loading}
                            />
                            <button
                                type="button"
                                className="password-toggle"
                                onClick={() => setShowPassword(!showPassword)}
                                disabled={loading}
                            >
                                {showPassword ? '👁️' : '👁️‍🗨️'}
                            </button>
                        </div>

                        <div className="form-options">
                            <label className="remember-me">
                                <input
                                    type="checkbox"
                                    checked={rememberMe}
                                    onChange={(e) => setRememberMe(e.target.checked)}
                                    disabled={loading}
                                />
                                <span>Remember me</span>
                            </label>
                            <a href="#" className="forgot-password">Forgot password?</a>
                        </div>

                        <button 
                            type="submit" 
                            className="login-btn"
                            disabled={loading}
                        >
                            {loading ? (
                                <>
                                    <span className="spinner"></span>
                                    Logging in...
                                </>
                            ) : (
                                'Login to Dashboard'
                            )}
                        </button>
                    </form>

                    <div className="demo-credentials">
                        <p>📝 Demo Credentials</p>
                        <div className="demo-box">
                            <div className="demo-item">
                                <span className="label">Email:</span>
                                <span className="value">admin@gmail.com</span>
                                <button 
                                    className="copy-btn"
                                    onClick={() => copyCredentials('admin@gmail.com')}
                                >
                                    Copy
                                </button>
                            </div>
                            <div className="demo-item">
                                <span className="label">Password:</span>
                                <span className="value">admin123</span>
                                <button 
                                    className="copy-btn"
                                    onClick={() => copyCredentials('admin123')}
                                >
                                    Copy
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

export default Login;
